class Playground {
  async run(inputs) {
    const chars = inputs[0].split('').filter(c => c.trim() !== '');
    this.array.init(chars);
    this.log('Validate if brackets are balanced using Stack');
    await this.await();

    const pairs = { ')': '(', ']': '[', '}': '{' };
    const opening = new Set(['(', '[', '{']);

    for (let i = 0; i < chars.length; i++) {
      const char = chars[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Scanning: '${char}'`);
      await this.await();

      if (opening.has(char)) {
        this.stack.push(char);
        this.array.highlight(i, '#f59e0b');
        this.log(`Opening bracket → Push '${char}' to stack`);
        await this.await();
      } 
      else if (char in pairs) {
        this.log(`Closing bracket '${char}' → Check stack top`);
        await this.await();

        if (this.stack.isEmpty()) {
          this.array.highlight(i, '#ef4444');
          this.log('❌ Stack empty! No matching opening bracket');
          await this.await();
          return false;
        }

        const top = this.stack.peek();
        this.stack.highlight(this.stack.size() - 1, '#f59e0b');
        this.log(`Stack top: '${top}'`);
        await this.await();

        if (top === pairs[char]) {
          this.stack.pop();
          this.array.highlight(i, '#10b981');
          this.log(`✅ Match! '${top}' pairs with '${char}'`);
          await this.await();
        } else {
          this.array.highlight(i, '#ef4444');
          this.stack.highlight(this.stack.size() - 1, '#ef4444');
          this.log(`❌ Mismatch! Expected '${pairs[char]}', found '${top}'`);
          await this.await();
          return false;
        }
      }
      this.array.clearHighlights();
    }

    this.ptr.remove('i');

    if (this.stack.isEmpty()) {
      this.log('✅ All brackets balanced!');
      await this.await();
      return true;
    } else {
      this.log(`❌ Unbalanced: ${this.stack.size()} unclosed bracket(s)`);
      await this.await();
      return false;
    }
  }
}
